25→/** Responsible for calculating CSS and element styles and modifying content on a flashcard  */
26→class CardAppearance(private val customFonts: ReviewerCustomFonts, private val cardZoom: Int, private val imageZoom: Int, private val centerVertically: Boolean) {
27→    /** Below could be in a better abstraction.  */
28→    fun appendCssStyle(style: StringBuilder) {
29→        // Zoom cards
30→        if (cardZoom != 100) {
31→            style.append("body { zoom: ${cardZoom / 100.0} }\n")
32→        }
33→
34→        // Zoom images
35→        if (imageZoom != 100) {
36→            style.append("img { zoom: ${imageZoom / 100.0} }\n")
37→        }
38→    }
39→
40→    @CheckResult
41→    fun getCssClasses(): String {
42→        val cardClass = StringBuilder()
43→        if (centerVertically) {
44→            cardClass.append(" vertically_centered")
45→        }
46→        if (currentTheme.isNightMode) {
47→            // Enable the night-mode class
48→            cardClass.append(" night_mode nightMode")
49→
50→            // Emit the dark_mode selector to allow dark theme overrides
51→            if (currentTheme == Theme.DARK) {
52→                cardClass.append(" ankidroid_dark_mode")
53→            }
54→        } else {
55→            // Emit the plain_mode selector to allow plain theme overrides
56→            if (currentTheme == Theme.PLAIN) {
57→                cardClass.append(" ankidroid_plain_mode")
58→            }
59→        }
60→        return cardClass.toString()
61→    }
62→
63→    val style: String
64→        get() {
65→            val style = StringBuilder()
66→            customFonts.updateCssStyle(style)
67→            appendCssStyle(style)
68→            return style.toString()
69→        }
70→
71→    fun getCardClass(oneBasedCardOrdinal: Int): String {
72→        return "card card$oneBasedCardOrdinal" + getCssClasses()
73→    }
74→
75→    companion object {
76→        private val nightModeClassRegex = Regex("\\.night(?:_m|M)ode\\b")
77→
78→        fun create(customFonts: ReviewerCustomFonts, preferences: SharedPreferences): CardAppearance {
79→            val cardZoom = preferences.getInt("cardZoom", 100)
80→            val imageZoom = preferences.getInt("imageZoom", 100)
81→            val centerVertically = preferences.getBoolean("centerVertically", false)
82→            return CardAppearance(customFonts, cardZoom, imageZoom, centerVertically)
83→        }
84→
85→        fun fixBoldStyle(content: String): String {
86→            // In order to display the bold style correctly, we have to change
87→            // font-weight to 700
88→            return content.replace("font-weight:600;", "font-weight:700;")
89→        }
90→
91→        /**
92→         * hasUserDefinedNightMode finds out if the user has included class .night_mode in card's stylesheet
93→         */
94→        fun hasUserDefinedNightMode(card: Card): Boolean {
95→            return card.css().contains(nightModeClassRegex)
96→        }
97→    }
98→}
