package com.ichi2.anki.cardviewer

import com.ichi2.libanki.Sound
import org.junit.Assert.assertFalse
import org.junit.Assert.assertTrue
import org.junit.Test

/**
 * Tests for the "Show play buttons on cards with audio" preference
 */
class ShowAudioPlayButtonsPreferenceTest {

    @Test
    fun `expandSounds with showPlayButtons true should include play button HTML`() {
        val content = "Test [anki:play:q:0] content"
        val result = Sound.expandSounds(content, showPlayButtons = true)

        // Should contain play button HTML elements
        assertTrue("Result should contain play button HTML", result.contains("replay-button"))
        assertTrue("Result should contain SVG element", result.contains("<svg"))
    }

    @Test
    fun `expandSounds with showPlayButtons false should strip audio references`() {
        val content = "Test [anki:play:q:0] content"
        val result = Sound.expandSounds(content, showPlayButtons = false)

        // Should not contain audio references or play button HTML
        assertFalse("Result should not contain audio references", result.contains("[anki:play"))
        assertFalse("Result should not contain play button HTML", result.contains("replay-button"))

        // Should still contain the text content
        assertTrue("Result should contain original text", result.contains("Test"))
        assertTrue("Result should contain original text", result.contains("content"))
    }

    @Test
    fun `expandSounds default behavior should show play buttons`() {
        val content = "Test [anki:play:q:0] content"
        val result = Sound.expandSounds(content)

        // Default behavior should show play buttons
        assertTrue("Default behavior should include play button HTML", result.contains("replay-button"))
    }

    @Test
    fun `expandSounds with no audio references should return unchanged content`() {
        val content = "Test content without audio"
        val resultWithButtons = Sound.expandSounds(content, showPlayButtons = true)
        val resultWithoutButtons = Sound.expandSounds(content, showPlayButtons = false)

        // Content without audio references should be unchanged in both cases
        assertTrue("Content should remain unchanged", resultWithButtons == content)
        assertTrue("Content should remain unchanged", resultWithoutButtons == content)
    }
}
